// components/NextArrow.jsx
import React from 'react';
import styles from './HeroSection.module.css'; // Импортируем стили

function NextArrow(props) {
  const { className, style, onClick } = props;
  return (
    <button
      className={className}
      onClick={onClick}
      style={{ ...style, ...{
        display: "block",
        background: 'transparent', // Прозрачный фон
        border: '2px solid #ff7a00', // Оранжевая рамка
        borderRadius: "50%", // Круглый
        width: "30px",
        height: "30px",
        right: "-30px", // Позиционирование справа
        top: "50%",
        transform: "translateY(-50%)",
        cursor: "pointer",
        outline: "none", // Убираем обводку при фокусе
        // Добавляем иконку (стрелку вправо)
        position: 'relative',
      } }}
    >
      <span style={{
        position: 'absolute',
        top: '50%',
        left: '50%',
        transform: 'translate(-40%, -50%)',
        fontSize: '16px',
        color: '#ff7a00',
      }}>&#8250;</span> {}
    </button>
  );
}

export default NextArrow;
